export const ToolResultEvent = z.object({ "kind": z.literal("tool_result").default("tool_result"), "id": z.string(), "tool": z.string(), "elapsed_ms": z.number().int().default(0), "link": z.union([z.string(), z.null()]).optional(), "parent_id": z.union([z.string(), z.null()]).optional() });
export type ToolResultEvent = z.infer<typeof ToolResultEvent>;

export const ToolRetryEvent = z.object({ "kind": z.literal("tool_retry").default("tool_retry"), "id": z.string(), "tool": z.string(), "error": z.string(), "elapsed_ms": z.number().int().default(0), "parent_id": z.union([z.string(), z.null()]).optional() });
export type ToolRetryEvent = z.infer<typeof ToolRetryEvent>;

export const WebResult = z.object({ "title": z.string().describe("Title of the web page."), "url": z.string().describe("URL of the web page."), "snippet": z.union([z.string(), z.null()]).describe("Excerpt(s) from the page that matched the query.").optional(), "source_name": z.union([z.string(), z.null()]).describe("Publisher / domain name, when extractable from the URL.").optional(), "publish_date": z.union([z.string(), z.null()]).describe("Publication date of the page, when available.").optional(), "content": z.union([z.lazy(() => ResultContent), z.null()]).describe("Downloadable content descriptor for this result, fetched via the Contents endpoint. Web results are always downloadable as text. None for callers that do not populate it.").optional(), "citation_number": z.union([z.number().int(), z.null()]).describe("1-based citation number that the answer's inline [N] markers reference. Set only when the answer inline-cites this result (the Agent API); None on raw-retrieval surfaces.").optional() }).describe("A single raw web search result returned by the WEB source index.\n\nDistinct from `KnowledgeCardSource` (a citation inside a synthesized\nanswer) and `KnowledgeCard` (a Tako visualization). Web results are\nraw retrieval output — title, URL, optional snippet — independent of\nany LLM synthesis that may also happen over them.");
export type WebResult = z.infer<typeof WebResult>;
